1	/**
2	 * Inter-Location Transfers API
3	 */
4	
5	import { getUserLocationFilter } from '@/app/api/lib/helpers/licenceeFilter';
6	import { InterLocationTransferModel } from '@/app/api/lib/models/interLocationTransfer';
7	import { generateMongoId } from '@/lib/utils/id';
8	import type { CreateInterLocationTransferRequest } from '@/shared/types/vault';
9	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
10	import {
11	  logRouteCreate,
12	  logRouteFetch,
13	  logRouteError,
14	  extractUserFromRequest,
15	} from '@/app/api/lib/utils/routeLogger';
16	import { NextRequest, NextResponse } from 'next/server';
17	import type { InterLocationTransferDocument } from '@shared/types';
18	
19	/**
20	 * POST /api/vault/transfers
21	 */
22	/**
23	 * POST /api/vault/transfers
24	 *
25	 * @body {string} fromLocationId - Source location ID (REQUIRED)
26	 * @body {string} toLocationId - Destination location ID (REQUIRED)
27	 * @body {number} amount - Transfer amount (REQUIRED)
28	 * @body {Array} denominations - Denomination breakdown (REQUIRED)
29	 * @body {string} notes - Transfer notes
30	 */
31	export async function POST(request: NextRequest) {
32	  const startTime = Date.now();
33	  const functionName = 'POST /api/vault/transfers';
34	  const user = extractUserFromRequest(request);
35	
36	  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
37	    try {
38	      // ============================================================================
39	      // STEP 1: Validate permissions
40	      // ============================================================================
41	      const vaultManagerId = userPayload._id as string;
42	      const normalizedRoles = userRoles.map(r => String(r).toLowerCase());
43	      const hasVMAccess = normalizedRoles.some(role =>
44	        ['developer', 'admin', 'manager'].includes(role)
45	      );
46	
47	      if (!hasVMAccess) {
48	        logRouteError(
49	          functionName,
50	          'POST',
51	          '/api/vault/transfers',
52	          'Insufficient permissions',
53	          user
54	        );
55	        return NextResponse.json(
56	          { success: false, error: 'Insufficient permissions' },
57	          { status: 403 }
58	        );
59	      }
60	
61	      // ============================================================================
62	      // STEP 2: Parse and validate body
63	      // ============================================================================
64	      const body: CreateInterLocationTransferRequest = await request.json();
65	      const { fromLocationId, toLocationId, amount, denominations, notes } =
66	        body;
67	
68	      if (!fromLocationId || !toLocationId || !amount || !denominations) {
69	        logRouteError(
70	          functionName,
71	          'POST',
72	          '/api/vault/transfers',
73	          'Missing required fields',
74	          user
75	        );
76	        return NextResponse.json(
77	          { success: false, error: 'Missing required fields' },
78	          { status: 400 }
79	        );
80	      }
81	
82	      if (fromLocationId === toLocationId) {
83	        logRouteError(
84	          functionName,
85	          'POST',
86	          '/api/vault/transfers',
87	          'Source and destination locations must be different',
88	          user
89	        );
90	        return NextResponse.json(
91	          {
92	            success: false,
93	            error: 'Source and destination locations must be different',
94	          },
95	          { status: 400 }
96	        );
97	      }
98	
99	      // ============================================================================
100	      // STEP 3: Validate location access
101	      // ============================================================================
102	      const allowedLocationIds = await getUserLocationFilter(
103	        (userPayload?.assignedLicencees as string[]) || [],
104	        undefined,
105	        (userPayload?.assignedLocations as string[]) || [],
106	        userRoles
107	      );
108	
109	      if (allowedLocationIds !== 'all') {
110	        if (
111	          !allowedLocationIds.includes(fromLocationId) ||
112	          !allowedLocationIds.includes(toLocationId)
113	        ) {
114	          logRouteError(
115	            functionName,
116	            'POST',
117	            '/api/vault/transfers',
118	            'Access denied for one or both locations',
119	            user
120	          );
121	          return NextResponse.json(
122	            {
123	              success: false,
124	              error: 'Access denied for one or both locations',
125	            },
126	            { status: 403 }
127	          );
128	        }
129	      }
130	
131	      // ============================================================================
132	      // STEP 4: Create transfer and save
133	      // ============================================================================
134	      const transferId = await generateMongoId();
135	      const transfer = new InterLocationTransferModel({
136	        _id: transferId,
137	        fromLocationId,
138	        toLocationId,
139	        fromLocationName: `Location ${fromLocationId}`,
140	        toLocationName: `Location ${toLocationId}`,
141	        amount,
142	        denominations,
143	        status: 'pending',
144	        requestedBy: vaultManagerId,
145	        notes,
146	      });
147	
148	      await transfer.save();
149	
150	      const duration = Date.now() - startTime;
151	      logRouteCreate(
152	        functionName,
153	        'POST',
154	        '/api/vault/transfers',
155	        1,
156	        user,
157	        duration
158	      );
159	
160	      // ============================================================================
161	      // STEP 5: Return response
162	      // ============================================================================
163	      return NextResponse.json({ success: true, transfer });
164	    } catch (error: unknown) {
165	      const errorMessage =
166	        error instanceof Error ? error.message : 'Failed to create transfer';
167	      logRouteError(
168	        functionName,
169	        'POST',
170	        '/api/vault/transfers',
171	        errorMessage,
172	        user
173	      );
174	      console.error('Error creating inter-location transfer:', error);
175	      const message = error instanceof Error ? error.message : 'Unknown error';
176	      return NextResponse.json(
177	        { success: false, error: message },
178	        { status: 500 }
179	      );
180	    }
181	  });
182	}
183	
184	/**
185	 * GET /api/vault/transfers
186	 */
187	
188	/**
189	 * Main GET handler for inter-location transfers
190	 *
191	 * @param {string} locationId - ID of the location to fetch transfers for (REQUIRED)
192	 * @param {number} page - Page number for pagination
193	 */
194	export async function GET(request: NextRequest) {
195	  const startTime = Date.now();
196	  const functionName = 'GET /api/vault/transfers';
197	  const user = extractUserFromRequest(request);
198	
199	  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
200	    try {
201	      // ============================================================================
202	      // STEP 1: Validate parameters
203	      // ============================================================================
204	      const { searchParams } = new URL(request.url);
205	      const locationId = searchParams.get('locationId');
206	      if (!locationId) {
207	        logRouteError(
208	          functionName,
209	          'GET',
210	          '/api/vault/transfers',
211	          'Location ID is required',
212	          user
213	        );
214	        return NextResponse.json(
215	          { success: false, error: 'Location ID is required' },
216	          { status: 400 }
217	        );
218	      }
219	
220	      // ============================================================================
221	      // STEP 2: Validate location access
222	      // ============================================================================
223	      const allowedLocationIds = await getUserLocationFilter(
224	        (userPayload?.assignedLicencees as string[]) || [],
225	        undefined,
226	        (userPayload?.assignedLocations as string[]) || [],
227	        userRoles
228	      );
229	
230	      if (
231	        allowedLocationIds !== 'all' &&
232	        !allowedLocationIds.includes(locationId)
233	      ) {
234	        logRouteError(
235	          functionName,
236	          'GET',
237	          '/api/vault/transfers',
238	          'Access denied for this location',
239	          user
240	        );
241	        return NextResponse.json(
242	          { success: false, error: 'Access denied for this location' },
243	          { status: 403 }
244	        );
245	      }
246	
247	      // ============================================================================
248	      // STEP 3: Fetch transfers
249	      // ============================================================================
250	      const page = parseInt(searchParams.get('page') || '1');
251	      const limit = Math.min(parseInt(searchParams.get('limit') || '20'), 100);
252	      const skip = (page - 1) * limit;
253	
254	      const query = {
255	        $or: [{ fromLocationId: locationId }, { toLocationId: locationId }],
256	      };
257	      const [transfers, total] = await Promise.all([
258	        InterLocationTransferModel.find(query)
259	          .sort({ createdAt: -1 })
260	          .skip(skip)
261	          .limit(limit)
262	          .lean<InterLocationTransferDocument[]>(),
263	        InterLocationTransferModel.countDocuments(query),
264	      ]);
265	
266	      const duration = Date.now() - startTime;
267	      logRouteFetch(
268	        functionName,
269	        'GET',
270	        '/api/vault/transfers',
271	        transfers.length,
272	        user,
273	        duration
274	      );
275	
276	      // ============================================================================
277	      // STEP 4: Return response
278	      // ============================================================================
279	      return NextResponse.json({
280	        success: true,
281	        transfers,
282	        pagination: {
283	          page,
284	          limit,
285	          total,
286	          totalPages: Math.ceil(total / limit),
287	        },
288	      });
289	    } catch (error: unknown) {
290	      const errorMessage =
291	        error instanceof Error ? error.message : 'Failed to fetch transfers';
292	      logRouteError(
293	        functionName,
294	        'GET',
295	        '/api/vault/transfers',
296	        errorMessage,
297	        user
298	      );
299	      console.error('Error fetching transfers:', error);
300	      const message = error instanceof Error ? error.message : 'Unknown error';
301	      return NextResponse.json(
302	        { success: false, error: message },
303	        { status: 500 }
304	      );
305	    }
306	  });
307	}
