1	/**
2	 * Transfer Approval API
3	 *
4	 * POST /api/vault/transfers/approve
5	 *
6	 * Approves or denies an inter-location transfer request.
7	 *
8	 * @module app/api/vault/transfers/approve/route
9	 */
10	
11	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
12	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
13	import { connectDB } from '@/app/api/lib/middleware/db';
14	import { InterLocationTransferModel } from '@/app/api/lib/models/interLocationTransfer';
15	import VaultShiftModel from '@/app/api/lib/models/vaultShift';
16	import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
17	import { generateMongoId } from '@/lib/utils/id';
18	import {
19	  logRouteUpdate,
20	  logRouteError,
21	  extractUserFromRequest,
22	} from '@/app/api/lib/utils/routeLogger';
23	import type { ApproveInterLocationTransferRequest } from '@/shared/types/vault';
24	import { NextRequest, NextResponse } from 'next/server';
25	
26	/**
27	 * POST /api/vault/transfers/approve
28	 *
29	 * @body {string} transferId - REQUIRED. ID of the transfer request to approve
30	 * @body {boolean} approved - REQUIRED. Whether to approve (true) or deny (false)
31	 * @body {string} notes - Optional approval notes
32	 */
33	export async function POST(request: NextRequest) {
34	  const startTime = Date.now();
35	  const functionName = 'POST /api/vault/transfers/approve';
36	  const user = extractUserFromRequest(request);
37	
38	  try {
39	    // ============================================================================
40	    // STEP 1: Authentication & Authorization
41	    // ============================================================================
42	    const userPayload = await getUserFromServer();
43	    if (!userPayload) {
44	      logRouteError(
45	        functionName,
46	        'POST',
47	        '/api/vault/transfers/approve',
48	        'Unauthorized',
49	        user
50	      );
51	      return NextResponse.json(
52	        { success: false, error: 'Unauthorized' },
53	        { status: 401 }
54	      );
55	    }
56	    const vaultManagerId = userPayload._id as string;
57	    const userRoles = (userPayload?.roles as string[]) || [];
58	    const hasVMAccess = userRoles.some(role =>
59	      ['developer', 'admin', 'manager'].includes(role.toLowerCase())
60	    );
61	    if (!hasVMAccess) {
62	      logRouteError(
63	        functionName,
64	        'POST',
65	        '/api/vault/transfers/approve',
66	        'Insufficient permissions',
67	        user
68	      );
69	      return NextResponse.json(
70	        { success: false, error: 'Insufficient permissions' },
71	        { status: 403 }
72	      );
73	    }
74	
75	    // ============================================================================
76	    // STEP 2: Parse and validate request body
77	    // ============================================================================
78	    const body: ApproveInterLocationTransferRequest = await request.json();
79	    const { transferId, approved, notes } = body;
80	
81	    if (!transferId) {
82	      logRouteError(
83	        functionName,
84	        'POST',
85	        '/api/vault/transfers/approve',
86	        'Transfer ID is required',
87	        user
88	      );
89	      return NextResponse.json(
90	        { success: false, error: 'Transfer ID is required' },
91	        { status: 400 }
92	      );
93	    }
94	
95	    // ============================================================================
96	    // STEP 3: Database connection
97	    // ============================================================================
98	    await connectDB();
99	
100	    // ============================================================================
101	    // STEP 4: Find and validate transfer
102	    // ============================================================================
103	    const transfer = await InterLocationTransferModel.findOne({
104	      _id: transferId,
105	    });
106	    if (!transfer) {
107	      logRouteError(
108	        functionName,
109	        'POST',
110	        '/api/vault/transfers/approve',
111	        'Transfer not found',
112	        user
113	      );
114	      return NextResponse.json(
115	        { success: false, error: 'Transfer not found' },
116	        { status: 404 }
117	      );
118	    }
119	
120	    if (transfer.status !== 'pending') {
121	      logRouteError(
122	        functionName,
123	        'POST',
124	        '/api/vault/transfers/approve',
125	        'Transfer is not in pending status',
126	        user
127	      );
128	      return NextResponse.json(
129	        { success: false, error: 'Transfer is not in pending status' },
130	        { status: 400 }
131	      );
132	    }
133	
134	    // ============================================================================
135	    // STEP 5: Update transfer status
136	    // ============================================================================
137	    const now = new Date();
138	    const transferDoc = transfer as unknown as Record<string, unknown>;
139	    transferDoc.status = approved ? 'approved' : 'cancelled';
140	    transferDoc.approvedBy = vaultManagerId;
141	    transferDoc.approvedAt = now;
142	
143	    if (notes) {
144	      const currentNotes = (transferDoc.notes as string) || '';
145	      transferDoc.notes = currentNotes + (currentNotes ? '; ' : '') + notes;
146	    }
147	
148	    // ============================================================================
149	    // STEP 6: If approved, create vault transactions
150	    // ============================================================================
151	    let transaction;
152	    if (approved) {
153	      // Get active vault shift for the TO location
154	      const activeVaultShift = await VaultShiftModel.findOne({
155	        locationId: transferDoc.toLocationId,
156	        status: 'active',
157	      });
158	
159	      if (!activeVaultShift) {
160	        return NextResponse.json(
161	          {
162	            success: false,
163	            error: 'No active vault shift found at destination location',
164	          },
165	          { status: 400 }
166	        );
167	      }
168	
169	      // Create transaction for receiving location
170	      const transactionId = await generateMongoId();
171	      transferDoc.transactionId = transactionId;
172	      transferDoc.completedAt = now;
173	
174	      transaction = new VaultTransactionModel({
175	        _id: transactionId,
176	        locationId: transferDoc.toLocationId,
177	        timestamp: now,
178	        type: 'expense', // Inter-location transfer received
179	        from: { type: 'external' },
180	        to: { type: 'vault' },
181	        amount: transferDoc.amount,
182	        denominations: transferDoc.denominations,
183	        vaultBalanceBefore:
184	          activeVaultShift.closingBalance || activeVaultShift.openingBalance,
185	        vaultBalanceAfter:
186	          ((activeVaultShift.closingBalance ||
187	            activeVaultShift.openingBalance) as number) +
188	          (transferDoc.amount as number),
189	        vaultShiftId: activeVaultShift._id,
190	        performedBy: vaultManagerId,
191	        notes: `Inter-location transfer from ${transferDoc.fromLocationName}${notes ? `: ${notes}` : ''}`,
192	      });
193	
194	      await transaction.save();
195	
196	      // Update vault shift balance
197	      activeVaultShift.closingBalance = transaction.vaultBalanceAfter;
198	      await activeVaultShift.save();
199	
200	      transferDoc.status = 'completed';
201	    }
202	
203	    // ============================================================================
204	    // STEP 7: Save transfer
205	    // ============================================================================
206	    await transfer.save();
207	
208	    // Audit Activity
209	    await logActivity({
210	      userId: vaultManagerId as string,
211	      username: userPayload.username as string,
212	      action: 'update',
213	      details: `${approved ? 'Approved' : 'Denied'} transfer from ${transferDoc.fromLocationId} to ${transferDoc.toLocationId}: $${transferDoc.amount}`,
214	      metadata: {
215	        resource: 'vault',
216	        resourceId: transferDoc.toLocationId,
217	        resourceName: 'Inter-Location Transfer',
218	        transferId: transferDoc._id,
219	        status: approved ? 'approved' : 'denied',
220	        amount: transferDoc.amount,
221	      },
222	    });
223	
224	    const duration = Date.now() - startTime;
225	    logRouteUpdate(
226	      functionName,
227	      'POST',
228	      '/api/vault/transfers/approve',
229	      1,
230	      user,
231	      duration
232	    );
233	
234	    // ============================================================================
235	    // STEP 8: Return success response
236	    // ============================================================================
237	    return NextResponse.json({
238	      success: true,
239	      transfer,
240	      transaction,
241	    });
242	  } catch (error: unknown) {
243	    const errorMessage =
244	      error instanceof Error ? error.message : 'Failed to approve transfer';
245	    logRouteError(
246	      functionName,
247	      'POST',
248	      '/api/vault/transfers/approve',
249	      errorMessage,
250	      user
251	    );
252	    const errorMessageForResponse =
253	      error instanceof Error ? error.message : 'Internal server error';
254	    console.error(
255	      'Error approving inter-location transfer:',
256	      errorMessageForResponse
257	    );
258	    return NextResponse.json(
259	      { success: false, error: errorMessageForResponse },
260	      { status: 500 }
261	    );
262	  }
263	}
