1	/**
2	 * Movement Requests API Route
3	 *
4	 * This route handles operations related to movement requests for cabinets/machines.
5	 * It supports:
6	 * - GET: Fetching all movement requests with optional licencee filtering
7	 * - POST: Creating a new movement request
8	 *
9	 * @module app/api/movement-requests/route
10	 */
11	
12	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
13	import { getUserLocationFilter } from '@/app/api/lib/helpers/licenceeFilter';
14	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
15	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
16	import { MovementRequest } from '@/app/api/lib/models/movementrequests';
17	import { getClientIP } from '@/lib/utils/ipAddress';
18	import {
19	  logRouteFetch,
20	  logRouteCreate,
21	  logRouteError,
22	  extractUserFromRequest,
23	} from '@/app/api/lib/utils/routeLogger';
24	import type { GamingLocationDocument } from '@shared/types';
25	import { NextRequest, NextResponse } from 'next/server';
26	
27	/**
28	 * Main GET handler for fetching movement requests
29	 *
30	 * Flow:
31	 * 1. Parse and validate request parameters
32	 * 2. Fetch all non-deleted movement requests
33	 * 3. Filter by licencee if provided
34	 * 4. Fetch location names for lookup
35	 * 5. Transform requests with location names
36	 * 6. Return transformed requests
37	 */
38	export async function GET(req: NextRequest) {
39	  return withApiAuth(
40	    req,
41	    async ({ user: userPayload, userRoles, isAdminOrDev }) => {
42	      const startTime = Date.now();
43	      const functionName = 'GET /api/movement-requests';
44	      const user = extractUserFromRequest(req);
45	      try {
46	        // ============================================================================
47	        // STEP 1: Parse user payload
48	        // ============================================================================
49	        const assignedLicencees =
50	          (userPayload as { assignedLicencees?: string[] })
51	            ?.assignedLicencees || [];
52	        const assignedLocations =
53	          (userPayload as { assignedLocations?: string[] })
54	            ?.assignedLocations || [];
55	
56	        // ============================================================================
57	        // STEP 2: Get user location permissions
58	        // ============================================================================
59	        const { searchParams } = new URL(req.url);
60	        const licencee = searchParams.get('licencee');
61	        const allowedLocationIds = await getUserLocationFilter(
62	          isAdminOrDev ? 'all' : assignedLicencees,
63	          licencee && licencee !== 'all' ? licencee : undefined,
64	          assignedLocations,
65	          userRoles
66	        );
67	
68	        // ============================================================================
69	        // STEP 3: Fetch all non-deleted movement requests with Aggregation
70	        // ============================================================================
71	        const stagingRequests = await MovementRequest.aggregate([
72	          // Match non-deleted requests
73	          {
74	            $match: {
75	              $or: [{ deletedAt: null }, { deletedAt: { $exists: false } }],
76	            },
77	          },
78	          // Lookup recipient user
79	          {
80	            $lookup: {
81	              from: 'users',
82	              localField: 'requestTo',
83	              foreignField: '_id',
84	              as: 'recipientDetails',
85	            },
86	          },
87	          // Lookup creator user
88	          {
89	            $lookup: {
90	              from: 'users',
91	              localField: 'createdBy',
92	              foreignField: '_id',
93	              as: 'creatorDetails',
94	            },
95	          },
96	          // Lookup machine details if selectedMachines exists
97	          {
98	            $lookup: {
99	              from: 'machines',
100	              localField: 'selectedMachines',
101	              foreignField: '_id',
102	              as: 'machineDetails',
103	            },
104	          },
105	          // Unwind details
106	          {
107	            $unwind: {
108	              path: '$recipientDetails',
109	              preserveNullAndEmptyArrays: true,
110	            },
111	          },
112	          {
113	            $unwind: {
114	              path: '$creatorDetails',
115	              preserveNullAndEmptyArrays: true,
116	            },
117	          },
118	          // Calculate names and machine details
119	          {
120	            $addFields: {
121	              recipientName: {
122	                $cond: {
123	                  if: {
124	                    $and: [
125	                      '$recipientDetails.profile.firstName',
126	                      '$recipientDetails.profile.lastName',
127	                    ],
128	                  },
129	                  then: {
130	                    $concat: [
131	                      '$recipientDetails.profile.firstName',
132	                      ' ',
133	                      '$recipientDetails.profile.lastName',
134	                    ],
135	                  },
136	                  else: {
137	                    $ifNull: ['$recipientDetails.username', '$requestTo'],
138	                  },
139	                },
140	              },
141	              creatorName: {
142	                $cond: {
143	                  if: {
144	                    $and: [
145	                      '$creatorDetails.profile.firstName',
146	                      '$creatorDetails.profile.lastName',
147	                    ],
148	                  },
149	                  then: {
150	                    $concat: [
151	                      '$creatorDetails.profile.firstName',
152	                      ' ',
153	                      '$creatorDetails.profile.lastName',
154	                    ],
155	                  },
156	                  else: { $ifNull: ['$creatorDetails.username', '$createdBy'] },
157	                },
158	              },
159	              machineDetails: {
160	                $map: {
161	                  input: '$machineDetails',
162	                  as: 'm',
163	                  in: {
164	                    _id: '$$m._id',
165	                    serialNumber: '$$m.serialNumber',
166	                    displayName: {
167	                      $cond: {
168	                        if: {
169	                          $and: [
170	                            '$$m.custom.name',
171	                            { $ne: ['$$m.custom.name', ''] },
172	                          ],
173	                        },
174	                        then: '$$m.custom.name',
175	                        else: { $ifNull: ['$$m.serialNumber', '$$m._id'] },
176	                      },
177	                    },
178	                  },
179	                },
180	              },
181	            },
182	          },
183	          // Sort by newest first
184	          { $sort: { createdAt: -1 } },
185	        ]);
186	
187	        // ============================================================================
188	        // STEP 4: Filter by user location permissions and direct recipient
189	        // ============================================================================
190	        const userEmail = userPayload.emailAddress as string;
191	        let requests = stagingRequests;
192	
193	        if (allowedLocationIds !== 'all') {
194	          // Filter requests to only include those where:
195	          // 1. locationFromId, locationToId, or locationId is in the user's accessible locations
196	          // 2. OR the user is the direct recipient (requestTo)
197	          // 3. OR the user is the creator (createdBy) — creators can always see their own requests
198	          const currentUserId = String(userPayload._id);
199	          requests = requests.filter(
200	            request =>
201	              allowedLocationIds.includes(String(request.locationFromId)) ||
202	              allowedLocationIds.includes(String(request.locationToId)) ||
203	              allowedLocationIds.includes(String(request.locationId)) ||
204	              // Fallback for names if IDs are missing (legacy compatibility)
205	              allowedLocationIds.includes(String(request.locationFrom)) ||
206	              allowedLocationIds.includes(String(request.locationTo)) ||
207	              request.requestTo === currentUserId ||
208	              request.requestTo === userEmail ||
209	              request.createdBy === currentUserId ||
210	              request.createdBy === userEmail
211	          );
212	        }
213	
214	        // ============================================================================
215	        // STEP 5: Filter by licencee if provided (additional filter)
216	        // ============================================================================
217	        if (licencee && licencee !== 'all') {
218	          const licenceeLocations = await GamingLocations.find(
219	            { 'rel.licencee': licencee },
220	            { _id: 1, name: 1 }
221	          ).lean<GamingLocationDocument[]>();
222	
223	          const licenceeLocationIds = licenceeLocations.map(
224	            (loc: { _id: unknown }) => String(loc._id)
225	          );
226	
227	          requests = requests.filter(
228	            request =>
229	              licenceeLocationIds.includes(String(request.locationFrom)) ||
230	              licenceeLocationIds.includes(String(request.locationTo))
231	          );
232	        }
233	
234	        // ============================================================================
235	        // STEP 6: Fetch location names for lookup
236	        // ============================================================================
237	        const locations = await GamingLocations.find(
238	          {},
239	          { _id: 1, name: 1 }
240	        ).lean<GamingLocationDocument[]>();
241	        const idToName = Object.fromEntries(
242	          locations.map(l => [String(l._id), l.name])
243	        );
244	
245	        // ============================================================================
246	        // STEP 7: Transform requests with location names and map legacy statuses
247	        // ============================================================================
248	        const transformed = requests.map(
249	          (requestItem: Record<string, unknown>) => {
250	            // Map legacy statuses to purely pending/completed
251	            const mappedStatus = requestItem.status as string;
252	            let finalStatus = mappedStatus;
253	            if (mappedStatus === 'approved') finalStatus = 'completed';
254	            if (mappedStatus === 'in progress') finalStatus = 'pending';
255	            if (mappedStatus === 'rejected') finalStatus = 'completed'; // Or pending? Leave rejected as pending for safety if it shouldn't be completed
256	
257	            return {
258	              ...requestItem,
259	              status:
260	                finalStatus === 'approved'
261	                  ? 'completed'
262	                  : finalStatus === 'in progress'
263	                    ? 'pending'
264	                    : finalStatus || 'pending',
265	              locationFrom:
266	                idToName[String(requestItem.locationFrom)] ||
267	                String(requestItem.locationFrom),
268	              locationTo:
269	                idToName[String(requestItem.locationTo)] ||
270	                String(requestItem.locationTo),
271	              recipientName: requestItem.recipientName || requestItem.requestTo, // Fallback
272	              creatorName: requestItem.creatorName || requestItem.createdBy, // Fallback
273	            };
274	          }
275	        );
276	
277	        // ============================================================================
278	        // STEP 8: Return transformed requests
279	        // ============================================================================
280	        const duration = Date.now() - startTime;
281	        logRouteFetch(
282	          functionName,
283	          'GET',
284	          '/api/movement-requests',
285	          transformed.length,
286	          user,
287	          duration
288	        );
289	        if (duration > 1000) {
290	          console.warn(`[Movement Requests API] Completed in ${duration}ms`);
291	        }
292	        return NextResponse.json(transformed);
293	      } catch (error: unknown) {
294	        const duration = Date.now() - startTime;
295	        logRouteError(
296	          functionName,
297	          'GET',
298	          '/api/movement-requests',
299	          'Failed to fetch movement requests',
300	          user
301	        );
302	        console.error(
303	          `[Movement Requests GET API] Error after ${duration}ms:`,
304	          error
305	        );
306	        return NextResponse.json(
307	          { error: 'Failed to fetch movement requests' },
308	          { status: 500 }
309	        );
310	      }
311	    }
312	  );
313	}
