/**
 * Transfer Approval API
 *
 * POST /api/vault/transfers/approve
 *
 * Approves or denies an inter-location transfer request.
 *
 * @module app/api/vault/transfers/approve/route
 */

import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import { InterLocationTransferModel } from '@/app/api/lib/models/interLocationTransfer';
import VaultShiftModel from '@/app/api/lib/models/vaultShift';
import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
import { generateMongoId } from '@/lib/utils/id';
import {
  logRouteUpdate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import type { ApproveInterLocationTransferRequest } from '@/shared/types/vault';
import { NextRequest, NextResponse } from 'next/server';

/**
 * POST /api/vault/transfers/approve
 *
 * @body {string} transferId - REQUIRED. ID of the transfer request to approve
 * @body {boolean} approved - REQUIRED. Whether to approve (true) or deny (false)
 * @body {string} notes - Optional approval notes
 */
export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'POST /api/vault/transfers/approve';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
    try {
      // ============================================================================
      // STEP 1: Authorization check
      // ============================================================================
      const vaultManagerId = userPayload._id as string;
      const hasVMAccess = userRoles.some(role =>
        ['developer', 'admin', 'manager'].includes(String(role).toLowerCase())
      );
      if (!hasVMAccess) {
        logRouteError(
          functionName,
          'POST',
          '/api/vault/transfers/approve',
          'Insufficient permissions',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Insufficient permissions' },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 2: Parse and validate request body
      // ============================================================================
      const body: ApproveInterLocationTransferRequest = await request.json();
      const { transferId, approved, notes } = body;

      if (!transferId) {
        logRouteError(
          functionName,
          'POST',
          '/api/vault/transfers/approve',
          'Transfer ID is required',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Transfer ID is required' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Find and validate transfer
      // ============================================================================
      const transfer = await InterLocationTransferModel.findOne({
        _id: transferId,
      });
      if (!transfer) {
        logRouteError(
          functionName,
          'POST',
          '/api/vault/transfers/approve',
          'Transfer not found',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Transfer not found' },
          { status: 404 }
        );
      }

      if (transfer.status !== 'pending') {
        logRouteError(
          functionName,
          'POST',
          '/api/vault/transfers/approve',
          'Transfer is not in pending status',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Transfer is not in pending status' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 4: Update transfer status
      // ============================================================================
      const now = new Date();
      const transferDoc = transfer as unknown as Record<string, unknown>;
      transferDoc.status = approved ? 'approved' : 'cancelled';
      transferDoc.approvedBy = vaultManagerId;
      transferDoc.approvedAt = now;

      if (notes) {
        const currentNotes = (transferDoc.notes as string) || '';
        transferDoc.notes = currentNotes + (currentNotes ? '; ' : '') + notes;
      }

      // ============================================================================
      // STEP 5: If approved, create vault transactions
      // ============================================================================
      let transaction;
      if (approved) {
        // Get active vault shift for the TO location
        const activeVaultShift = await VaultShiftModel.findOne({
          locationId: transferDoc.toLocationId,
          status: 'active',
        });

        if (!activeVaultShift) {
          return NextResponse.json(
            {
              success: false,
              error: 'No active vault shift found at destination location',
            },
            { status: 400 }
          );
        }

        // Create transaction for receiving location
        const transactionId = await generateMongoId();
        transferDoc.transactionId = transactionId;
        transferDoc.completedAt = now;

        transaction = new VaultTransactionModel({
          _id: transactionId,
          locationId: transferDoc.toLocationId,
          timestamp: now,
          type: 'expense', // Inter-location transfer received
          from: { type: 'external' },
          to: { type: 'vault' },
          amount: transferDoc.amount,
          denominations: transferDoc.denominations,
          vaultBalanceBefore:
            activeVaultShift.closingBalance || activeVaultShift.openingBalance,
          vaultBalanceAfter:
            ((activeVaultShift.closingBalance ||
              activeVaultShift.openingBalance) as number) +
            (transferDoc.amount as number),
          vaultShiftId: activeVaultShift._id,
          performedBy: vaultManagerId,
          notes: `Inter-location transfer from ${transferDoc.fromLocationName}${notes ? `: ${notes}` : ''}`,
        });

        await transaction.save();

        // Update vault shift balance
        activeVaultShift.closingBalance = transaction.vaultBalanceAfter;
        await activeVaultShift.save();

        transferDoc.status = 'completed';
      }

      // ============================================================================
      // STEP 6: Save transfer
      // ============================================================================
      await transfer.save();

      // Audit Activity
      await logActivity({
        userId: vaultManagerId as string,
        username: userPayload.username as string,
        action: 'update',
        details: `${approved ? 'Approved' : 'Denied'} transfer from ${transferDoc.fromLocationId} to ${transferDoc.toLocationId}: $${transferDoc.amount}`,
        metadata: {
          resource: 'vault',
          resourceId: transferDoc.toLocationId,
          resourceName: 'Inter-Location Transfer',
          transferId: transferDoc._id,
          status: approved ? 'approved' : 'denied',
          amount: transferDoc.amount,
        },
      });

      const duration = Date.now() - startTime;
      logRouteUpdate(
        functionName,
        'POST',
        '/api/vault/transfers/approve',
        1,
        user,
        duration
      );
      if (duration > 1000) {
        console.warn(`[POST /api/vault/transfers/approve] slow: ${duration}ms`);
      }

      // ============================================================================
      // STEP 7: Return success response
      // ============================================================================
      return NextResponse.json({
        success: true,
        transfer,
        transaction,
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Failed to approve transfer';
      logRouteError(
        functionName,
        'POST',
        '/api/vault/transfers/approve',
        errorMessage,
        user
      );
      console.error('[POST /api/vault/transfers/approve] Error:', errorMessage);
      return NextResponse.json(
        { success: false, error: errorMessage },
        { status: 500 }
      );
    }
  });
}

/**
 * Movement Request by ID API Route
 *
 * This route handles operations for a specific movement request identified by ID.
 * It supports:
 * - DELETE: Soft deleting a movement request
 * - PATCH: Updating a movement request
 *
 * @module app/api/movement-requests/[id]/route
 */

import { logActivity } from '@/app/api/lib/helpers/activityLogger';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import { MovementRequest } from '@/app/api/lib/models/movementrequests';
import { getClientIP } from '@/lib/utils/ipAddress';
import {
  logRouteDelete,
  logRouteUpdate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import { NextRequest, NextResponse } from 'next/server';

/**
 * DELETE /api/movement-requests/[id]
 *
 * Deletes a movement request. Admins and developers may delete any request;
 * the original creator may soft-delete their own. Hard delete is restricted to
 * developers only.
 *
 * Path params:
 * @param id         {string}  Required. The ID of the movement request to delete.
 *
 * Query params:
 * @param deleteType {string}  Optional. 'soft' (default) sets `deletedAt`; 'hard' permanently removes the document (developer only).
 */
export async function DELETE(request: NextRequest): Promise<Response> {
  const startTime = Date.now();
  const functionName = 'DELETE /api/movement-requests/[id]';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: currentUser, userRoles }) => {
    try {
      // ============================================================================
      // STEP 1: Parse and validate request parameters
      // ============================================================================
      const { pathname } = request.nextUrl;
      const id = pathname.split('/').pop();
      if (!id) {
        return NextResponse.json(
          {
            success: false,
            message: 'MovementRequest ID is required',
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 2: Find movement request by ID
      // ============================================================================
      const movementRequestToDelete = await MovementRequest.findOne({ _id: id });
      if (!movementRequestToDelete) {
        logRouteError(
          functionName,
          'DELETE',
          '/api/movement-requests/[id]',
          'MovementRequest not found',
          user
        );
        return NextResponse.json(
          {
            success: false,
            message: 'MovementRequest not found',
          },
          { status: 404 }
        );
      }

      // ============================================================================
      // STEP 3: Permission check
      // ============================================================================
      const { searchParams } = new URL(request.url);
      const deleteType = (searchParams.get('deleteType') || 'soft') as
        | 'soft'
        | 'hard';

      const isAdminOrDev = userRoles.some(role =>
        ['admin', 'developer'].includes(String(role).toLowerCase())
      );
      const isCreator =
        movementRequestToDelete.createdBy === String(currentUser._id) ||
        movementRequestToDelete.createdBy === currentUser.emailAddress;

      if (!isAdminOrDev && !isCreator) {
        logRouteError(
          functionName,
          'DELETE',
          '/api/movement-requests/[id]',
          'Forbidden: You do not have permission to delete this movement request',
          user
        );
        return NextResponse.json(
          {
            success: false,
            message:
              'Forbidden: You do not have permission to delete this movement request',
          },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 4: Delete movement request
      // ============================================================================
      if (deleteType === 'hard') {
        const isDeveloper = userRoles.some(
          role => String(role).toLowerCase() === 'developer'
        );
        if (!isDeveloper) {
          logRouteError(
            functionName,
            'DELETE',
            '/api/movement-requests/[id]',
            'Forbidden: Only developers can hard-delete movement requests',
            user
          );
          return NextResponse.json(
            {
              success: false,
              message:
                'Forbidden: Only developers can hard-delete movement requests',
            },
            { status: 403 }
          );
        }
        const deleteResult = await MovementRequest.deleteOne({ _id: id });
        if (deleteResult.deletedCount === 0) {
          logRouteError(
            functionName,
            'DELETE',
            '/api/movement-requests/[id]',
            'Failed to delete movement request',
            user
          );
          return NextResponse.json(
            { success: false, message: 'Failed to delete movement request' },
            { status: 500 }
          );
        }
      } else {
        const softDeleted = await MovementRequest.findOneAndUpdate(
          { _id: id },
          { deletedAt: new Date() },
          { new: true }
        );
        if (!softDeleted) {
          logRouteError(
            functionName,
            'DELETE',
            '/api/movement-requests/[id]',
            'Failed to soft-delete movement request',
            user
          );
          return NextResponse.json(
            { success: false, message: 'Failed to soft-delete movement request' },
            { status: 500 }
          );
        }
      }

      // ============================================================================
      // STEP 5: Log activity
      // ============================================================================
      if (currentUser.emailAddress) {
        try {
          const deleteChanges = [
            {
              field: 'cabinetIn',
              oldValue: movementRequestToDelete.cabinetIn,
              newValue: null,
            },
            {
              field: 'locationFrom',
              oldValue: movementRequestToDelete.locationFrom,
              newValue: null,
            },
            {
              field: 'locationTo',
              oldValue: movementRequestToDelete.locationTo,
              newValue: null,
            },
            {
              field: 'reason',
              oldValue: movementRequestToDelete.reason,
              newValue: null,
            },
            {
              field: 'status',
              oldValue: movementRequestToDelete.status,
              newValue: null,
            },
          ];

          await logActivity({
            action: 'DELETE',
            details: `Deleted movement request for cabinet ${movementRequestToDelete.cabinetIn} from ${movementRequestToDelete.locationFrom} to ${movementRequestToDelete.locationTo}`,
            userId: currentUser._id as string,
            username: (currentUser.emailAddress ||
              currentUser.username ||
              'unknown') as string,
            ipAddress: getClientIP(request) || undefined,
            userAgent: request.headers.get('user-agent') || undefined,
            metadata: {
              userId: currentUser._id as string,
              userEmail: currentUser.emailAddress as string,
              userRole: userRoles[0] ? String(userRoles[0]) : 'user',
              resource: 'movement_request',
              resourceId: id,
              resourceName: `Cabinet ${movementRequestToDelete.cabinetIn}`,
              changes: deleteChanges,
            },
          });
        } catch (logError) {
          console.error('[DELETE /api/movement-requests/[id]] Failed to log activity:', logError instanceof Error ? logError.message : 'Unknown error');
        }
      }

      // ============================================================================
      // STEP 6: Return success response
      // ============================================================================
      const duration = Date.now() - startTime;
      logRouteDelete(
        functionName,
        'DELETE',
        '/api/movement-requests/[id]',
        1,
        user,
        duration
      );
      if (duration > 1000) {
        console.warn(`[DELETE /api/movement-requests/[id]] slow: ${duration}ms`);
      }
      return NextResponse.json({ success: true });
    } catch (err) {
      const duration = Date.now() - startTime;
      const errorMsg = err instanceof Error ? err.message : 'Unknown error';
      console.error(
        `[DELETE /api/movement-requests/[id]] Error after ${duration}ms:`,
        errorMsg
      );
      return NextResponse.json(
        {
          success: false,
          message: 'Delete failed',
          error: errorMsg,
        },
        { status: 500 }
      );
    }
  });
}

/**
 * PATCH /api/movement-requests/[id]
 *
 * Updates one or more fields of an existing movement request. Accessible to
 * admins, developers, the original creator, the designated recipient, and
 * location admins/technicians/managers assigned to the destination location.
 *
 * Path params:
 * @param id          {string}  Required. The ID of the movement request to update.
 *
 * Body fields:
 * @param cabinetIn   {string}  Optional. Cabinet/machine being moved.
 * @param locationFrom {string} Optional. ID of the source location.
 * @param locationTo  {string}  Optional. ID of the destination location.
 * @param reason      {string}  Optional. Reason for the movement request.
 * @param status      {string}  Optional. Updated status of the request (e.g. 'pending', 'approved', 'completed').
 * @param requestTo   {string}  Optional. ID or email of the user the request is directed to.
 */
export async function PATCH(request: NextRequest): Promise<Response> {
  const startTime = Date.now();
  const functionName = 'PATCH /api/movement-requests/[id]';
  const user = extractUserFromRequest(request);

  return withApiAuth(request, async ({ user: currentUser, userRoles }) => {
    try {
      // ============================================================================
      // STEP 1: Parse and validate request parameters and body
      // ============================================================================
      const { pathname } = request.nextUrl;
      const id = pathname.split('/').pop();
      if (!id) {
        return NextResponse.json(
          {
            success: false,
            message: 'MovementRequest ID is required',
          },
          { status: 400 }
        );
      }

      let body;
      try {
        body = await request.json();
      } catch {
        return NextResponse.json(
          {
            success: false,
            message: 'Invalid JSON in request body',
          },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 2: Find original movement request
      // ============================================================================
      const originalMovementRequest = await MovementRequest.findOne({ _id: id });
      if (!originalMovementRequest) {
        return NextResponse.json(
          {
            success: false,
            message: 'MovementRequest not found',
          },
          { status: 404 }
        );
      }

      // ============================================================================
      // STEP 3: Permission check
      // ============================================================================
      const isAdminOrDev = userRoles.some(role =>
        ['admin', 'developer'].includes(String(role).toLowerCase())
      );
      // Comparison by ID if possible, fallback to email if old data
      const isCreator =
        originalMovementRequest.createdBy === currentUser._id ||
        originalMovementRequest.createdBy === currentUser.emailAddress;
      const isRecipient =
        originalMovementRequest.requestTo === currentUser._id ||
        originalMovementRequest.requestTo === currentUser.emailAddress;

      // Check if user is a Loc Admin/Tech assigned to the destination location
      const destinationLocationId = String(originalMovementRequest.locationTo);
      const userAssignedLocations =
        (currentUser.assignedLocations as string[]) || [];
      const isDestinationAuthorized =
        userRoles.some(role =>
          ['location admin', 'technician', 'manager'].includes(String(role).toLowerCase())
        ) && userAssignedLocations.includes(destinationLocationId);

      if (
        !isAdminOrDev &&
        !isCreator &&
        !isRecipient &&
        !isDestinationAuthorized
      ) {
        return NextResponse.json(
          {
            success: false,
            message:
              'Forbidden: You do not have permission to update this request',
          },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 4: Update movement request
      // ============================================================================
      const updated = await MovementRequest.findOneAndUpdate(
        {
          _id: id,
          $or: [{ deletedAt: null }, { deletedAt: { $exists: false } }],
        },
        body,
        { new: true }
      );

      // ============================================================================
      // STEP 5: Log activity
      // ============================================================================
      if (currentUser.emailAddress || currentUser.username) {
        try {
          const updateChanges = Object.keys(body)
            .filter(
              key =>
                String(
                  originalMovementRequest[
                    key as keyof typeof originalMovementRequest
                  ]
                ) !== String(body[key as keyof typeof body])
            )
            .map(key => ({
              field: key,
              oldValue:
                originalMovementRequest[
                  key as keyof typeof originalMovementRequest
                ],
              newValue: body[key as keyof typeof body],
            }));

          await logActivity({
            action: 'UPDATE',
            details: `Updated movement request for cabinet ${body.cabinetIn || originalMovementRequest.cabinetIn}`,
            userId: currentUser._id as string,
            username: (currentUser.emailAddress ||
              currentUser.username ||
              'unknown') as string,
            ipAddress: getClientIP(request) || undefined,
            userAgent: request.headers.get('user-agent') || undefined,
            metadata: {
              userId: currentUser._id as string,
              userEmail: currentUser.emailAddress as string,
              userRole: userRoles[0] ? String(userRoles[0]) : 'user',
              resource: 'movement_request',
              resourceId: id,
              resourceName: `Cabinet ${body.cabinetIn || originalMovementRequest.cabinetIn}`,
              changes: updateChanges,
            },
          });
        } catch (logError) {
          console.error('[PATCH /api/movement-requests/[id]] Failed to log activity:', logError instanceof Error ? logError.message : 'Unknown error');
        }
      }

      // ============================================================================
      // STEP 6: Return updated request
      // ============================================================================
      const duration = Date.now() - startTime;
      logRouteUpdate(
        functionName,
        'PATCH',
        '/api/movement-requests/[id]',
        1,
        user,
        duration
      );
      if (duration > 1000) {
        console.warn(`[PATCH /api/movement-requests/[id]] slow: ${duration}ms`);
      }
      return NextResponse.json(updated);
    } catch (err) {
      const duration = Date.now() - startTime;
      const errorMsg = err instanceof Error ? err.message : 'Unknown error';
      console.error(
        `[PATCH /api/movement-requests/[id]] Error after ${duration}ms:`,
        errorMsg
      );
      return NextResponse.json(
        {
          success: false,
          message: 'Update failed',
          error: errorMsg,
        },
        { status: 500 }
      );
    }
  });
}

